import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.appcompat.widget.SearchView;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.bumptech.glide.Glide;
import com.example.plantastic.api.PerenualService;
import com.example.plantastic.api.PlantAdapter;
import com.example.plantastic.api.PlantResponse;
import com.example.plantastic.data.PlantasticDatabase;
import com.example.plantastic.data.entities.Fotod;
import com.example.plantastic.data.entities.Kasutaja;
import com.example.plantastic.data.entities.Taim;
import com.example.plantastic.data.entities.TaimLiik;
import com.example.plantastic.data.entities.TaimSort;

import java.util.ArrayList;
import java.util.List;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

import static android.app.Activity.RESULT_OK;

public class AddPlantFragment extends Fragment {

    private String apiKey;
    private static final String BASE_URL = "https://perenual.com/api/";

    private SearchView searchView;
    private RecyclerView recyclerView;
    private ScrollView detailsForm;
    private ProgressBar progressBar;
    private PlantAdapter adapter;
    private PerenualService apiService;

    private ImageView selectedPlantImage;
    private EditText editNickname, editSpecies, editDescription;
    private Button btnSavePlant, btnCancel;
    private View btnTakePhoto;

    private Uri selectedImageUri;
    private String selectedImagePath;
    private String selectedApiImageUrl;
    private PlantResponse.PlantData selectedPlantData;

    private final ActivityResultLauncher<Intent> imagePickerLauncher = registerForActivityResult(
            new ActivityResultContracts.StartActivityForResult(),
            result -> {
                if (result.getResultCode() == RESULT_OK && result.getData() != null) {
                    Uri imageUri = result.getData().getData();
                    if (imageUri != null) {
                        selectedImageUri = imageUri;
                        selectedImagePath = saveImageToInternalStorage(imageUri);
                        if (selectedImagePath != null) {
                            Glide.with(this).load(selectedImagePath).into(selectedPlantImage);
                        } else {
                            selectedPlantImage.setImageURI(selectedImageUri);
                        }
                    }
                }
            }
    );

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.add_plant_fragment, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);
        initViews(view);
        loadApiKey();
        setupRetrofit();
        setupRecyclerView();
        setupSearch();
    }

    private void initViews(View view) {
        searchView = view.findViewById(R.id.searchView);
        recyclerView = view.findViewById(R.id.recyclerView);
        detailsForm = view.findViewById(R.id.detailsForm);
        progressBar = view.findViewById(R.id.progressBar);

        selectedPlantImage = view.findViewById(R.id.selectedPlantImage);
        editNickname = view.findViewById(R.id.editNickname);
        editSpecies = view.findViewById(R.id.editSpecies);
        editDescription = view.findViewById(R.id.editDescription);
        btnSavePlant = view.findViewById(R.id.btnSavePlant);
        btnCancel = view.findViewById(R.id.btnCancel);
        btnTakePhoto = view.findViewById(R.id.btnTakePhoto);

        btnCancel.setOnClickListener(v -> showSearchList());
        btnTakePhoto.setOnClickListener(v -> openGallery());
        btnSavePlant.setOnClickListener(v -> savePlant());
    }

    private void loadApiKey() {
        try {
            ApplicationInfo ai = requireContext().getPackageManager().getApplicationInfo(requireContext().getPackageName(), PackageManager.GET_META_DATA);
            apiKey = ai.metaData.getString("perenual_api_key");

            // Clean key from possible quotes or spaces from local.properties
            if (apiKey != null) {
                apiKey = apiKey.replace("\"", "").trim();
            }

            if (apiKey == null || apiKey.isEmpty() || apiKey.contains("{")) {
                Log.e("SEARCH_DEBUG", "API Key Error: " + apiKey);
                Toast.makeText(getContext(), "API Key missing. Sync Gradle after editing local.properties", Toast.LENGTH_LONG).show();
            }
        } catch (Exception e) {
            Log.e("API_ERROR", "Failed to load meta-data: " + e.getMessage());
        }
    }

    private void setupRetrofit() {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(BASE_URL)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
        apiService = retrofit.create(PerenualService.class);
    }

    private void setupRecyclerView() {
        recyclerView.setLayoutManager(new LinearLayoutManager(getContext()));
        adapter = new PlantAdapter(new ArrayList<>(), this::showDetailsForm);
        recyclerView.setAdapter(adapter);
    }

    private void setupSearch() {
        if (searchView == null) return;
        searchView.onActionViewExpanded(); 
        searchView.setSubmitButtonEnabled(true);
        searchView.setOnQueryTextListener(new SearchView.OnQueryTextListener() {
            @Override
            public boolean onQueryTextSubmit(String query) {
                if (!query.trim().isEmpty()) {
                    searchPlants(query.trim());
                }
                return true;
            }
            @Override
            public boolean onQueryTextChange(String newText) {
                // Manual search only to save API limits.
                return true;
            }
        });
    }

    private void showDetailsForm(PlantResponse.PlantData plant) {
        selectedPlantData = plant;
        selectedImageUri = null;
        selectedImagePath = null;
        selectedApiImageUrl = null;
        searchView.setVisibility(View.GONE);
        recyclerView.setVisibility(View.GONE);
        if (progressBar != null) progressBar.setVisibility(View.GONE);
        detailsForm.setVisibility(View.VISIBLE);

        editNickname.setText(plant.getCommonName());
        editSpecies.setText(plant.getCommonName());

        if (plant.getDefaultImage() != null) {
            selectedApiImageUrl = plant.getDefaultImage().getThumbnail();
            Glide.with(this)
                    .load(selectedApiImageUrl)
                    .into(selectedPlantImage);
        } else {
            selectedPlantImage.setImageResource(R.drawable.ic_flower);
        }

        refreshSelectedPlantDetails(plant);
    }

    private void refreshSelectedPlantDetails(PlantResponse.PlantData plant) {
        if (plant == null || apiService == null || apiKey == null || apiKey.isEmpty()) return;

        apiService.getSpeciesDetails(plant.getId(), apiKey).enqueue(new Callback<>() {
            @Override
            public void onResponse(@NonNull Call<PlantResponse.PlantData> call, @NonNull Response<PlantResponse.PlantData> response) {
                if (!isAdded() || !response.isSuccessful() || response.body() == null) return;

                selectedPlantData = response.body();
                if (selectedPlantData.getDefaultImage() != null && selectedPlantData.getDefaultImage().getThumbnail() != null) {
                    selectedApiImageUrl = selectedPlantData.getDefaultImage().getThumbnail();
                    Glide.with(AddPlantFragment.this)
                            .load(selectedApiImageUrl)
                            .into(selectedPlantImage);
                }
                editSpecies.setText(selectedPlantData.getCommonName());
            }

            @Override
            public void onFailure(@NonNull Call<PlantResponse.PlantData> call, @NonNull Throwable t) {
                Log.e("DETAILS_LOAD", "Failed to refresh species details: " + t.getMessage());
            }
        });
    }

    private void showSearchList() {
        detailsForm.setVisibility(View.GONE);
        searchView.setVisibility(View.VISIBLE);
        recyclerView.setVisibility(View.VISIBLE);
    }

    private void openGallery() {
        Intent intent = new Intent(Intent.ACTION_PICK, MediaStore.Images.Media.EXTERNAL_CONTENT_URI);
        imagePickerLauncher.launch(intent);
    }

    private String saveImageToInternalStorage(@NonNull Uri imageUri) {
        try (InputStream inputStream = requireContext().getContentResolver().openInputStream(imageUri)) {
            if (inputStream == null) return null;

            File imagesDir = new File(requireContext().getFilesDir(), "plant_images");
            if (!imagesDir.exists() && !imagesDir.mkdirs()) return null;

            File imageFile = new File(imagesDir, "plant_" + System.currentTimeMillis() + ".jpg");
            try (FileOutputStream outputStream = new FileOutputStream(imageFile)) {
                byte[] buffer = new byte[8192];
                int length;
                while ((length = inputStream.read(buffer)) > 0) {
                    outputStream.write(buffer, 0, length);
                }
            }
            return imageFile.getAbsolutePath();
        } catch (IOException e) {
            Log.e("IMAGE_SAVE", "Failed to copy selected image", e);
            return null;
        }
    }

    private void savePlant() {
        String nickname = editNickname.getText().toString();
        if (nickname.isEmpty()) {
            Toast.makeText(getContext(), "Please give your plant a nickname", Toast.LENGTH_SHORT).show();
            return;
        }

        if (selectedPlantData == null) {
            Toast.makeText(getContext(), "Please select a plant from search first", Toast.LENGTH_SHORT).show();
            return;
        }

        new Thread(() -> {
            try {
                PlantasticDatabase db = PlantasticDatabase.getInstance(requireContext());
                Kasutaja user = db.kasutajaDao().getFirstUser();
                int userId = (user != null) ? user.id : (int) db.kasutajaDao().insert(new Kasutaja() {{ kasutajanimi = "Primary User"; }});

                PlantResponse.PlantData plantDetails = selectedPlantData;
                if (apiService != null && apiKey != null && !apiKey.isEmpty() && selectedPlantData != null) {
                    try {
                        Response<PlantResponse.PlantData> detailsResponse = apiService.getSpeciesDetails(selectedPlantData.getId(), apiKey).execute();
                        if (detailsResponse.isSuccessful() && detailsResponse.body() != null) {
                            plantDetails = detailsResponse.body();
                        }
                    } catch (IOException e) {
                        Log.w("DETAILS_LOAD", "Falling back to selected plant data: " + e.getMessage());
                    }
                }

                if (plantDetails == null) {
                    throw new IllegalStateException("Plant details are unavailable");
                }

                String familyName = plantDetails.getFamily();
                if (familyName == null || familyName.isEmpty()) {
                    familyName = "General";
                }
                TaimLiik liik = db.taimLiikDao().getByName(familyName);
                int liikId;
                if (liik == null) {
                    liik = new TaimLiik();
                    liik.nimetus = familyName;
                    liik.ladinakeelne_nimetus = "Plantae";
                    liikId = (int) db.taimLiikDao().insert(liik);
                } else {
                    liikId = liik.id;
                }

                TaimSort sort = new TaimSort();
                sort.nimetus = plantDetails.getCommonName();
                List<String> scientificNames = plantDetails.getScientificName();
                sort.ladinakeelne_nimetus = (scientificNames != null && !scientificNames.isEmpty())
                        ? scientificNames.get(0) : "Unknown";
                sort.liik_id = liikId;
                sort.kastmisvajadus = plantDetails.getWateringLevel();
                sort.valgusnoudlikkus = plantDetails.getSunlightLevel();
                long sortId = db.taimSortDao().insert(sort);

                Taim taim = new Taim();
                taim.nimi = nickname;
                taim.sort_id = (int) sortId;
                taim.kasutaja_id = userId;
                taim.kirjeldus = editDescription.getText().toString();
                long taimId = db.taimDao().insert(taim);

                String imageToSave = null;
                if (selectedImagePath != null && !selectedImagePath.trim().isEmpty()) {
                    imageToSave = selectedImagePath;
                } else if (selectedImageUri != null) {
                    imageToSave = selectedImageUri.toString();
                } else if (selectedApiImageUrl != null && !selectedApiImageUrl.trim().isEmpty()) {
                    imageToSave = selectedApiImageUrl;
                }

                if (imageToSave != null) {
                    Fotod foto = new Fotod();
                    foto.taim_id = (int) taimId;
                    foto.foto = imageToSave;
                    db.fotodDao().insert(foto);
                }

                requireActivity().runOnUiThread(() -> {
                    Toast.makeText(getContext(), "Plant Saved Successfully!", Toast.LENGTH_SHORT).show();
                    getParentFragmentManager().popBackStack(); 
                });
            } catch (Exception e) {
                Log.e("DB_ERROR", "Failed to save: ", e);
                requireActivity().runOnUiThread(() -> Toast.makeText(getContext(), "Error: " + e.getMessage(), Toast.LENGTH_LONG).show());
            }
        }).start();
    }


    private void searchPlants(String query) {
        if (apiKey == null || apiKey.isEmpty() || apiKey.contains("{")) return;

        if (progressBar != null) progressBar.setVisibility(View.VISIBLE);
        Log.d("SEARCH_DEBUG", "Starting search for: " + query);

        apiService.searchPlants(apiKey, query).enqueue(new Callback<>() {
            @Override
            public void onResponse(@NonNull Call<PlantResponse> call, @NonNull Response<PlantResponse> response) {
                if (progressBar != null) progressBar.setVisibility(View.GONE);
                if (response.isSuccessful() && response.body() != null && isAdded()) {
                    List<PlantResponse.PlantData> results = response.body().getData();
                    adapter.setPlants(results);
                    if (results.isEmpty()) {
                        Toast.makeText(getContext(), "No plants found for '" + query + "'", Toast.LENGTH_SHORT).show();
                    }
                } else {
                    int code = response.code();
                    if (code == 429) {
                        Toast.makeText(getContext(), "API Limit Reached (100 calls). Wait until tomorrow.", Toast.LENGTH_LONG).show();
                    } else if (code == 401 || code == 403) {
                        Toast.makeText(getContext(), "Invalid API Key. Check local.properties.", Toast.LENGTH_LONG).show();
                    } else {
                        Toast.makeText(getContext(), "Search failed: " + code, Toast.LENGTH_SHORT).show();
                    }
                    Log.e("SEARCH_ERROR", "Status: " + code + " Error: " + response.message());
                }
            }
            @Override
            public void onFailure(@NonNull Call<PlantResponse> call, @NonNull Throwable t) {
                if (progressBar != null) progressBar.setVisibility(View.GONE);
                if (isAdded()) {
                    Log.e("SEARCH_ERROR", "Network failure: " + t.getMessage());
                    Toast.makeText(getContext(), "Check internet connection", Toast.LENGTH_SHORT).show();
                }
            }
        });
    }
}

package com.example.plantastic;

import android.content.pm.ApplicationInfo;
import android.content.pm.PackageManager;
import android.os.Bundle;
import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;

import com.bumptech.glide.Glide;
import com.example.plantastic.api.PerenualService;
import com.example.plantastic.api.PlantResponse;
import com.example.plantastic.api.PlantCareGuideResponse;

import java.util.ArrayList;
import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class EncyclopediaItemFragment extends Fragment {

    private static final String ARG_PLANT = "arg_plant";
    private static final String BASE_URL = "https://perenual.com/api/";
    private PlantResponse.PlantData plant;
    private String apiKey;
    private PerenualService apiService;

    public static EncyclopediaItemFragment newInstance(PlantResponse.PlantData plant) {
        EncyclopediaItemFragment fragment = new EncyclopediaItemFragment();
        Bundle args = new Bundle();
        args.putSerializable(ARG_PLANT, plant);
        fragment.setArguments(args);
        return fragment;
    }

    @Override
    public void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        if (getArguments() != null) {
            plant = (PlantResponse.PlantData) getArguments().getSerializable(ARG_PLANT);
        }
    }

    @Override
    public View onCreateView(LayoutInflater inflater, ViewGroup container,
                             Bundle savedInstanceState) {
        return inflater.inflate(R.layout.encyclopedia_plant_fragment, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        if (plant == null) return;

        ImageView backButton = view.findViewById(R.id.backButton);

        if (backButton != null) {
            backButton.setOnClickListener(v -> getParentFragmentManager().popBackStack());
        }

        setupRetrofit();
        loadApiKey();

        // Render whatever we already have immediately, then upgrade to the full detail record.
        bindPlantData(view, plant);

        if (apiKey != null && !apiKey.isEmpty() && apiService != null) {
            apiService.getSpeciesDetails(plant.getId(), apiKey).enqueue(new Callback<>() {
                @Override
                public void onResponse(@NonNull Call<PlantResponse.PlantData> call, @NonNull Response<PlantResponse.PlantData> response) {
                    if (!isAdded() || response.body() == null || !response.isSuccessful()) return;
                    plant = response.body();
                    bindPlantData(view, plant);
                }

                @Override
                public void onFailure(@NonNull Call<PlantResponse.PlantData> call, @NonNull Throwable t) {
                    Log.e("ENCYCLOPEDIA_ITEM", "Failed to load species details: " + t.getMessage());
                }
            });
        }
    }

    private void setupRetrofit() {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(BASE_URL)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
        apiService = retrofit.create(PerenualService.class);
    }

    private void loadApiKey() {
        try {
            ApplicationInfo ai = requireContext().getPackageManager().getApplicationInfo(
                    requireContext().getPackageName(), PackageManager.GET_META_DATA);
            apiKey = ai.metaData.getString("perenual_api_key");
            if (apiKey != null) {
                apiKey = apiKey.replace("\"", "").trim();
            }
        } catch (Exception e) {
            Log.e("ENCYCLOPEDIA_ITEM", "Failed to load API key: " + e.getMessage());
            Toast.makeText(getContext(), "API key missing", Toast.LENGTH_SHORT).show();
        }
    }

    private void bindPlantData(View view, PlantResponse.PlantData data) {
        if (data == null) return;

        ImageView plantImage = view.findViewById(R.id.plantImage);
        TextView commonNameText = view.findViewById(R.id.commonNameText);
        TextView scientificNameText = view.findViewById(R.id.scientificNameText);
        TextView descriptionText = view.findViewById(R.id.descriptionText);
        TextView careLevelText = view.findViewById(R.id.careLevel);
        TextView toxicToPetsText = view.findViewById(R.id.toxicToPets);

        commonNameText.setText(data.getCommonName());

        List<String> scientificNames = data.getScientificName();
        scientificNameText.setText(scientificNames.isEmpty() ? "Unknown" : scientificNames.get(0));

        String description = data.getDescription();
        if (description != null && !description.trim().isEmpty()) {
            descriptionText.setText(description);
        } else {
            descriptionText.setText("Description unavailable.");
        }

        careLevelText.setText(data.getCareLevel());
        toxicToPetsText.setText(data.getPoisonousToPetsText());

        if (data.getDefaultImage() != null && data.getDefaultImage().getThumbnail() != null && !data.getDefaultImage().getThumbnail().isEmpty()) {
            Glide.with(this)
                    .load(data.getDefaultImage().getThumbnail())
                    .placeholder(R.drawable.plant)
                    .into(plantImage);
        }

        int level = data.getSunlightLevel();
        ImageView sun1 = view.findViewById(R.id.sun1);
        ImageView sun2 = view.findViewById(R.id.sun2);
        ImageView sun3 = view.findViewById(R.id.sun3);
        ImageView sun4 = view.findViewById(R.id.sun4);

        if (sun1 != null) sun1.setAlpha(level >= 1 ? 1.0f : 0.3f);
        if (sun2 != null) sun2.setAlpha(level >= 2 ? 1.0f : 0.3f);
        if (sun3 != null) sun3.setAlpha(level >= 3 ? 1.0f : 0.3f);
        if (sun4 != null) sun4.setAlpha(level >= 4 ? 1.0f : 0.3f);

        int waterLevel = mapWateringToLevel(data.getWatering());
        ImageView drop1 = view.findViewById(R.id.drop1);
        ImageView drop2 = view.findViewById(R.id.drop2);
        ImageView drop3 = view.findViewById(R.id.drop3);

        if (drop1 != null) drop1.setAlpha(waterLevel >= 1 ? 1.0f : 0.3f);
        if (drop2 != null) drop2.setAlpha(waterLevel >= 2 ? 1.0f : 0.3f);
        if (drop3 != null) drop3.setAlpha(waterLevel >= 3 ? 1.0f : 0.3f);
    }

    private void loadCareGuide(String url, TextView descriptionText) {
        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(BASE_URL)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        PerenualService service = retrofit.create(PerenualService.class);
        service.getCareGuide(url).enqueue(new Callback<>() {
            @Override
            public void onResponse(@NonNull Call<PlantCareGuideResponse> call, @NonNull Response<PlantCareGuideResponse> response) {
                if (!response.isSuccessful() || response.body() == null) return;

                List<PlantCareGuideResponse.CareGuideItem> guides = response.body().getData();
                if (guides.isEmpty()) return;

                PlantCareGuideResponse.CareGuideItem guide = guides.get(0);
                List<PlantCareGuideResponse.CareGuideSection> sections = guide.getSection();
                if (sections.isEmpty()) return;

                List<String> parts = new ArrayList<>();
                for (PlantCareGuideResponse.CareGuideSection section : sections) {
                    String type = section.getType();
                    String description = section.getDescription();
                    if (!type.isEmpty() && !description.isEmpty()) {
                        parts.add(type.substring(0, 1).toUpperCase() + type.substring(1) + ": " + description);
                    }
                }

                if (!parts.isEmpty() && getActivity() != null) {
                    getActivity().runOnUiThread(() -> descriptionText.setText(String.join("\n\n", parts)));
                }
            }

            @Override
            public void onFailure(@NonNull Call<PlantCareGuideResponse> call, @NonNull Throwable t) {
                // Keep existing fallback text if the care guide fetch fails.
            }
        });
    }

    private int mapWateringToLevel(String watering) {
        if (watering == null) return 2;
        switch (watering.trim().toLowerCase()) {
            case "none": return 0;
            case "minimum": return 1;
            case "average": return 2;
            case "frequent": return 3;
            default: return 2;
        }
    }
}

